// AGENTE 1 - Perfil Profissional
// ⚠️ ESTE É UM PERFIL DE EXEMPLO (fake), para o repositório público.
// Antes de usar o workflow de verdade, edite os valores abaixo com os SEUS dados.
// Se você fizer fork deste repo, NÃO faça commit do node com seus dados reais -
// mantenha sua versão preenchida apenas localmente / numa branch privada.
//
// Quando quiser automatizar a leitura do currículo/portfólio, troque este node
// por um fluxo que lê o PDF/Google Doc e faz o parsing via IA.

const perfil = {
  nome: "Seu Nome Completo",
  localizacao_atual: "Sua Cidade, UF, Brasil",
  contato: {
    email: "seuemail@exemplo.com",
    linkedin: "linkedin.com/in/seu-usuario"
  },
  resumo_profissional: "Resumo profissional curto: formação, principais tecnologias, tipo de experiência (estágios, freelas, projetos pessoais) e o que te diferencia.",
  nivel: "Estudante / Júnior inicial",
  cargos_alvo: [
    "Estágio em Desenvolvimento de Software",
    "Desenvolvedor(a) Júnior Full Stack",
    "Desenvolvedor(a) Júnior Back-end",
    "Automação com IA / No-code (N8N)"
  ],
  modelo_trabalho_desejado: {
    remoto: "Aceita qualquer país/localização, sem restrição geográfica",
    presencial_ou_hibrido: "Somente Brasil, com preferência pela sua cidade"
  },
  educacao: [
    { curso: "Seu curso", instituicao: "Sua instituição", periodo: "Período (em andamento)" }
  ],
  experiencia: [
    {
      cargo: "Cargo",
      empresa: "Empresa",
      periodo: "Período",
      local: "Cidade, UF",
      atividades: [
        "Principal atividade 1",
        "Principal atividade 2"
      ],
      tecnologias: ["Tecnologia 1", "Tecnologia 2"]
    }
  ],
  stack_tecnica: {
    linguagens: ["JavaScript", "Python", "SQL", "HTML", "CSS"],
    ferramentas: ["N8N", "PostgreSQL", "Git", "GitHub"],
    ia_apis: ["GPT-4 API", "Engenharia de Prompt"]
  },
  idiomas: [
    { idioma: "Português", nivel: "Nativo" },
    { idioma: "Inglês", nivel: "Intermediário" }
  ],
  projetos_destaque: [
    { nome: "Seu projeto", link: "https://github.com/seu-usuario/seu-projeto" }
  ]
};

return [{ json: perfil }];

// CONFIG - Lista central de termos de busca (PT + EN)
// Edite APENAS este node para adicionar/remover termos de busca.
// Usado hoje por: Indeed Scraper e Linkedin Scraper (Apify).
// Pode ser reaproveitado por qualquer fonte nova que precise de busca por palavra-chave
// (ex.: um futuro node de Greenhouse/Lever por empresa).

const termos = [
  // Inglês
  "Software Engineer Intern",
  "Software Developer Intern",
  "Backend Intern",
  "Frontend Intern",
  "Full Stack Intern",
  "Junior Software Engineer",
  "Junior Backend Developer",
  "Junior Frontend Developer",
  "Entry Level Software Engineer",
  "Graduate Developer",
  "JavaScript Developer Junior",
  "Node.js Developer Junior",
  "React Developer Junior",
  "Python Developer Junior",
  "AI Automation Intern",
  "OpenAI Developer Intern",
  // Português
  "Estágio Desenvolvimento",
  "Estágio Programação",
  "Estágio TI",
  "Estágio Engenharia de Software",
  "Desenvolvedor Júnior",
  "Desenvolvedor Backend Júnior",
  "Desenvolvedor Front-end Júnior",
  "Desenvolvedor Full Stack Júnior"
];

console.log(`[Config] ${termos.length} termos de busca carregados.`);

return [{ json: { termos } }];

// Normaliza a saída do Apify (Indeed) para o formato interno padrão da automação.
// Os nomes de campo variam conforme a versão do actor - por isso os fallbacks com "||".
// Se o actor mudar de novo, confira 1x a aba "Output" da execução no n8n e ajuste aqui.

return $input.all().map(item => {
  const j = item.json;
  const titulo = j.title || j.positionName || j.jobTitle || '';
  if (!titulo) return null;

  const empresa = j.company || j.companyName || 'Não informado';
  const local = j.location || j.jobLocation || 'Não informado';
  const chaveFallback = (empresa + '_' + titulo).toLowerCase().replace(/\s+/g, '_');

  return {
    json: {
      id_externo: 'indeed_' + (j.id || j.jobKey || chaveFallback),
      titulo,
      empresa,
      local,
      remoto: /remot[eo]/i.test(String(local)),
      link: j.url || j.jobUrl || j.link || '',
      descricao: String(j.description || j.descriptionText || j.snippet || '').replace(/<[^>]+>/g, ' ').slice(0, 4000),
      tags: j.tags || [],
      fonte: 'Indeed'
    }
  };
}).filter(Boolean);

// Normaliza a saída do Apify (Linkedin) para o formato interno padrão da automação.
// Os nomes de campo variam conforme a versão do actor - por isso os fallbacks com "||".
// Se o actor mudar de novo, confira 1x a aba "Output" da execução no n8n e ajuste aqui.

return $input.all().map(item => {
  const j = item.json;
  const titulo = j.title || j.positionName || j.jobTitle || '';
  if (!titulo) return null;

  const empresa = j.companyName || j.company || 'Não informado';
  const local = j.location || j.jobLocation || 'Não informado';
  const chaveFallback = (empresa + '_' + titulo).toLowerCase().replace(/\s+/g, '_');

  return {
    json: {
      id_externo: 'linkedin_' + (j.id || j.jobId || chaveFallback),
      titulo,
      empresa,
      local,
      remoto: /remot[eo]/i.test(String(local)),
      link: j.link || j.url || j.jobUrl || '',
      descricao: String(j.descriptionText || j.description || '').replace(/<[^>]+>/g, ' ').slice(0, 4000),
      tags: j.tags || [],
      fonte: 'Linkedin'
    }
  };
}).filter(Boolean);

// AGENTE 2 - Normalização final (RemoteOK / Remotive / Arbeitnow) + Deduplicação global
// Indeed e Linkedin já chegam normalizados (ver nodes "Normalizar - Indeed" e
// "Normalizar - Linkedin", logo após os scrapers Apify). Aqui só:
//   1) padronizamos as 3 fontes "brutas" (RemoteOK/Remotive/Arbeitnow) pro mesmo formato
//   2) juntamos tudo e removemos duplicadas (dentro da execução e contra o que já está no Notion)
//
// Pra adicionar uma nova fonte "bruta" no futuro: copie um dos blocos abaixo (RemoteOK,
// Remotive ou Arbeitnow) e ajuste o `if` de detecção do formato de resposta da API nova.

const rawItems = $input.all();

// --- IDs e URLs já salvos no Notion (evita duplicar entre execuções) ---
let idsExistentes = new Set();
let urlsExistentes = new Set();
try {
  const notionResp = $('Buscar Vagas já salvas no Notion').first().json;
  for (const page of (notionResp.results || [])) {
    const idProp = page.properties && page.properties['ID Externo'];
    const idVal = (idProp && idProp.rich_text && idProp.rich_text[0] && idProp.rich_text[0].plain_text) || '';
    if (idVal) idsExistentes.add(idVal);

    const urlProp = page.properties && page.properties['Link da vaga'];
    const urlVal = (urlProp && urlProp.url) || '';
    if (urlVal) urlsExistentes.add(urlVal);
  }
} catch (e) {
  console.log('[Normalização] Não foi possível ler vagas existentes do Notion:', e.message);
}

function limparHtml(txt) {
  return String(txt || '').replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim().slice(0, 4000);
}

// Hash simples (não-criptográfico), só pra achar descrições muito parecidas
function hashTexto(txt) {
  const s = String(txt || '').toLowerCase().replace(/\s+/g, '').slice(0, 500);
  let hash = 0;
  for (let i = 0; i < s.length; i++) hash = (hash * 31 + s.charCodeAt(i)) | 0;
  return hash.toString(36);
}

const vagas = [];
const contagemPorFonte = {};
function registrar(fonte) { contagemPorFonte[fonte] = (contagemPorFonte[fonte] || 0) + 1; }

for (const item of rawItems) {
  const body = item.json;
  if (!body) continue;

  // Item de erro (um node upstream falhou com "continue on fail")
  if (body.error) {
    console.log('[Normalização] Fonte com erro, item ignorado:', body.error);
    continue;
  }

  // Já normalizado (Indeed/Linkedin) - reconhecível por já ter id_externo + fonte
  if (body.id_externo && body.fonte) {
    vagas.push(body);
    registrar(body.fonte);
    continue;
  }

  // RemoteOK: array direto de vagas
  if (Array.isArray(body)) {
    for (const job of body) {
      if (!job.id || !job.position) continue;
      vagas.push({
        id_externo: 'remoteok_' + job.id,
        titulo: job.position,
        empresa: job.company || 'Não informado',
        local: job.location || 'Remoto',
        remoto: true,
        link: job.url || ('https://remoteok.com/remote-jobs/' + job.id),
        descricao: limparHtml(job.description),
        tags: job.tags || [],
        fonte: 'RemoteOK'
      });
      registrar('RemoteOK');
    }
    continue;
  }

  // Remotive: { jobs: [...] }
  if (Array.isArray(body.jobs)) {
    for (const job of body.jobs) {
      vagas.push({
        id_externo: 'remotive_' + job.id,
        titulo: job.title,
        empresa: job.company_name || 'Não informado',
        local: job.candidate_required_location || 'Remoto',
        remoto: true,
        link: job.url,
        descricao: limparHtml(job.description),
        tags: job.tags || [],
        fonte: 'Remotive'
      });
      registrar('Remotive');
    }
    continue;
  }

  // Arbeitnow: { data: [...] }
  if (Array.isArray(body.data)) {
    for (const job of body.data) {
      vagas.push({
        id_externo: 'arbeitnow_' + job.slug,
        titulo: job.title,
        empresa: job.company_name || 'Não informado',
        local: job.location || 'Remoto',
        remoto: !!job.remote,
        link: job.url,
        descricao: limparHtml(job.description),
        tags: job.tags || [],
        fonte: 'Arbeitnow'
      });
      registrar('Arbeitnow');
    }
    continue;
  }
}

console.log('[Normalização] Vagas brutas por fonte:', JSON.stringify(contagemPorFonte), '| total normalizado:', vagas.length);

// --- Deduplicação (nesta ordem): id_externo -> url -> empresa+cargo -> hash da descrição ---
const vistoId = new Set();
const vistoUrl = new Set();
const vistoEmpresaCargo = new Set();
const vistoHashDescricao = new Set();

const novas = vagas.filter(v => {
  if (idsExistentes.has(v.id_externo)) return false;
  if (v.link && urlsExistentes.has(v.link)) return false;

  if (vistoId.has(v.id_externo)) return false;
  if (v.link && vistoUrl.has(v.link)) return false;

  const chaveEmpresaCargo = (v.empresa + '|' + v.titulo).toLowerCase().replace(/\s+/g, ' ').trim();
  if (vistoEmpresaCargo.has(chaveEmpresaCargo)) return false;

  const hashDesc = hashTexto(v.descricao);
  if (hashDesc && vistoHashDescricao.has(hashDesc)) return false;

  vistoId.add(v.id_externo);
  if (v.link) vistoUrl.add(v.link);
  vistoEmpresaCargo.add(chaveEmpresaCargo);
  if (hashDesc) vistoHashDescricao.add(hashDesc);
  return true;
});

console.log(`[Normalização] Após deduplicação: ${novas.length} vagas novas (${vagas.length - novas.length} duplicadas removidas).`);

return novas.map(v => ({ json: v }));

